// Parse incoming Full Contact Data from ManyChat - v15
const raw = $input.first().json;
const body = raw.body || raw || {};

const toBool = (value) => {
  if (typeof value === 'boolean') return value;
  const normalized = String(value ?? '').trim().toLowerCase();
  return ['true', '1', 'yes', 'si', 'sí', 'y'].includes(normalized);
};

const getCustomField = (fields, key) => {
  if (Array.isArray(fields)) {
    const hit = fields.find((item) => item?.name === key || item?.key === key || item?.field_name === key);
    return hit?.value ?? '';
  }
  if (fields && typeof fields === 'object') {
    return fields[key] ?? '';
  }
  return '';
};

const normalizePhoneDigits = (value) => {
  let digits = String(value || '').replace(/\D+/g, '');
  if (digits.startsWith('54')) digits = digits.slice(2);
  if (digits.startsWith('9')) digits = digits.slice(1);
  if (digits.startsWith('0')) digits = digits.slice(1);
  return digits;
};

const PHONE_AREA_CODES = [
  { code: '3718', name: 'Clorinda', province: 'Formosa' },
  { code: '3873', name: 'Tartagal', province: 'Salta' },
  { code: '3492', name: 'Rafaela', province: 'Santa Fe' },
