// DEBOUNCE CHECK v15 - Atomic latest-message validation
const mergedData = $('Merge Input').first().json;
const saveNode = $('Save Incoming Message').first();

let ourId = null;
const savedBody = saveNode.json;

if (Array.isArray(savedBody)) {
  if (savedBody.length > 0 && savedBody[0]?.id !== undefined) {
    ourId = savedBody[0].id;
  }
} else if (savedBody && typeof savedBody === 'object') {
  if (savedBody.id !== undefined) {
    ourId = savedBody.id;
  }
}

if (ourId === null || ourId === undefined) {
  return [{ json: { ...mergedData, should_continue: false, debug: 'could_not_extract_saved_message_id' } }];
}

const rpcResult = $('Check Is Latest (RPC)').first().json;

let isLatest = false;
if (typeof rpcResult === 'boolean') {
  isLatest = rpcResult;
} else if (Array.isArray(rpcResult) && rpcResult.length > 0) {
  isLatest = rpcResult[0] === true || rpcResult[0]?.check_is_latest_message === true;
} else if (rpcResult && typeof rpcResult === 'object') {
  isLatest = rpcResult.check_is_latest_message === true || rpcResult.result === true;
}

if (!isLatest) {
  return [{ json: { ...mergedData, should_continue: false, debug: 'not_latest' } }];
}

return [{ json: { ...mergedData, should_continue: true, our_id: ourId } }];

// MERGE & AGGREGATE consecutive user bursts v15
const mergedData = $('Debounce Check').first().json;

let recentRaw = [];
try {
  recentRaw = $('Fetch Recent Messages').all();
} catch (e) {
  recentRaw = [];
}

const byId = new Map();
for (const item of recentRaw) {
  const payload = item.json;
  const rows = Array.isArray(payload) ? payload : [payload];
  for (const row of rows) {
    if (!row || row.id === undefined || row.id === null) continue;
    byId.set(row.id, row);
  }
}

const recentMessages = [...byId.values()]
  .sort((a, b) => new Date(a.created_at || 0) - new Date(b.created_at || 0));

if (recentMessages.length === 0) {
  return [{ json: { ...mergedData, messages_merged: 1 } }];
}

const latestId = mergedData.our_id;
let latestIndex = recentMessages.findIndex((row) => String(row.id) === String(latestId));
if (latestIndex === -1) latestIndex = recentMessages.length - 1;

const burst = [];
for (let i = latestIndex; i >= 0; i--) {
  const row = recentMessages[i];
  if (!row || row.role !== 'user') break;
  const text = String(row.message || '').trim();
  if (text && text !== '(vacío)') burst.unshift(text);
}

const combined = burst.join(' ').trim();

return [{
  json: {
    ...mergedData,
    user_message: combined || mergedData.user_message,
    messages_merged: Math.max(burst.length, 1)
  }
}];

const rows = [];
for (const item of $input.all()) {
  const data = item.json;
  if (Array.isArray(data)) rows.push(...data);
  else if (data && data.role && data.message) rows.push(data);
}
return [{ json: { history_rows: rows } }];

const rows = [];
for (const item of $input.all()) {
  let data = item.json;
  if (data && data.data && Array.isArray(data.data)) data = data.data;
  if (Array.isArray(data)) rows.push(...data);
  else if (data && data.product_key) rows.push(data);
}
return [{ json: { products: rows } }];

// Orchestrator v15 - Keyword routing with anti-overroute
if ($input.context.itemIndex > 0) return [];

const merged = $('Merge & Aggregate Messages').first().json;

let customerData = {};
try {
  const raw = $('Fetch Customer Profile').first().json;
  if (Array.isArray(raw) && raw.length > 0) customerData = raw[0];
  else if (raw && raw.manychat_id) customerData = raw;
} catch (e) { customerData = {}; }

let historyRows = [];
try {
  const aggregatedHistory = $('Aggregate Conversation History').first().json.history_rows;
  historyRows = Array.isArray(aggregatedHistory) ? aggregatedHistory : [];
} catch (e) { historyRows = []; }

let productRows = [];
let productImages = {};
let productKeyNameMap = {};
let productStockMap = {};
let productConditionMap = {};
try {
  const aggregatedProducts = $('Aggregate Product Catalog').first().json.products;
  productRows = Array.isArray(aggregatedProducts) ? aggregatedProducts : [];
  for (const p of productRows) {
    if (!p || !p.product_key) continue;
    const baseName = String(p.product_name || '').trim();
    const cond = String(p.condition || 'new').trim().toLowerCase();
    const variantBits = [];
    if (cond === 'used') variantBits.push('seminuevo');
    else if (cond === 'like_new') variantBits.push('como nuevo');
    else if (cond === 'refurbished') variantBits.push('reacondicionado');
    else variantBits.push('nuevo');
    if (p.battery_health) variantBits.push('batería ' + p.battery_health + '%');
    productKeyNameMap[p.product_key] = baseName + ' (' + variantBits.join(', ') + ')';
    productStockMap[p.product_key] = p.in_stock;
    productConditionMap[p.product_key] = cond;
    const url = p.image_url || p.image || p.url;
    if (url && String(url).startsWith('http')) productImages[p.product_key] = String(url).trim();
  }
} catch (e) { productRows = []; }

let storeSettings = {};
try {
  const items = $('Fetch Store Settings').all();
  const rows = [];
  for (const item of items) {
    const d = item.json;
    if (Array.isArray(d)) rows.push(...d);
    else if (d && typeof d === 'object') rows.push(d);
  }
  const flattenedContext = rows.find((row) => row && (row.store_address || row.store_hours || row.store_payment_methods));
  if (flattenedContext) {
    storeSettings = flattenedContext;
  } else {
    for (const row of rows) {
      if (!row || !row.key) continue;
      storeSettings[String(row.key).trim()] = row.value;
    }
  }
} catch (e) { storeSettings = {}; }

const storeInfo = {
  address: String(storeSettings.store_address || 'Caseros 1365, Salta Capital. Diagonal a OCA, enfrente del Sindicato de Camioneros.').trim(),
  hours: String(storeSettings.store_hours || 'Lunes a Viernes 10:00-13:00 y 18:00-21:00 | Sábados 10:00-13:00 | Domingos cerrado.').trim(),
  paymentMethods: String(storeSettings.store_payment_methods || 'Transferencia bancaria en pesos, transferencia en dólares, Mercado Pago, Bitcoin y USDT (TRC-20) con 0% recargo, y efectivo en pesos o dólares.').trim(),
  creditPolicy: String(storeSettings.store_credit_policy || 'No hacemos créditos personales. Las cuotas son presenciales en Salta Capital.').trim(),
  shippingPolicy: String(storeSettings.store_shipping_policy || 'Envíos gratis a sucursal (BusPack/Flecha Carga, OCA o Vía Cargo). Despacho en 72hs hábiles. Salta Capital: entrega en el día. Interior Salta: 24hs.').trim(),
  warrantyNew: String(storeSettings.store_warranty_new || 'Los equipos nuevos tienen 1 año de garantía de fábrica.').trim(),
  warrantyUsed: String(storeSettings.store_warranty_used || 'Los equipos seminuevos o usados tienen garantía propia de TechnoStore.').trim(),
  instagram: String(storeSettings.store_social_instagram || '@technostore.salta').trim(),
  facebook: String(storeSettings.store_social_facebook || '@technostore.salta').trim(),
  supportedCards: String(storeSettings.customer_cards_supported || 'macro,naranja,visa,mastercard,amex,cabal,bancarizada').trim(),
  blockedCards: String(storeSettings.customer_cards_blocked || 'subcredito').trim(),
  financingScope: String(storeSettings.store_financing_scope || '6 cuotas fijas, solo presencial en Salta Capital. Naranja y Macro están permitidas. SubCrédito no.').trim(),
};

// ManyChat is_human_active is the source of truth for active handoff.
const humanAssigned = merged.is_human_active === true;
const isFirstInteraction = historyRows.length === 0;
const msg = String(merged.user_message || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const currentStage = String(customerData.funnel_stage || merged.funnel_stage || '').trim().toLowerCase();
const profileCity = String(customerData.city || merged.city || '').trim();
const lowerProfileCity = profileCity.toLowerCase();
const phoneAreaCode = String(merged.phone_area_code || customerData.phone_area_code || '').trim();
const phoneAreaName = String(merged.phone_area_name || customerData.phone_area_name || '').trim();
const phoneAreaProvince = String(merged.phone_area_province || customerData.phone_area_province || '').trim();
const lowerPhoneAreaProvince = phoneAreaProvince.toLowerCase();
const phoneLocationHint = String(merged.phone_location_hint || (phoneAreaCode ? 'phone_area_known' : (merged.phone ? 'unknown_area' : 'unknown'))).trim();
const shouldAskLocation = !profileCity;
const phoneLocationText = phoneAreaCode
  ? 'indicativo ' + phoneAreaCode + ' => ' + phoneAreaName + (phoneAreaProvince ? ', ' + phoneAreaProvince : '')
  : 'sin pista confiable';
const locationContextNote = profileCity
  ? 'El cliente ya tiene ciudad confirmada en CRM. Usá esa ciudad como verdad actual.'
  : phoneAreaCode
    ? lowerPhoneAreaProvince === 'salta'
      ? 'El teléfono sugiere Salta por el indicativo. Usalo solo como pista. Preguntale si es Salta Capital o interior antes de asumir cuotas presenciales.'
      : 'El teléfono sugiere una zona o provincia por el indicativo. Usalo solo como pista y pedí confirmación de ciudad o localidad antes de asumir envío, retiro o cuotas.'
    : 'No hay una pista confiable de ubicación por teléfono. Pedí ciudad o localidad antes de asumir envío, retiro o cuotas.';
const historyRowsSorted = [...historyRows]
  .sort((a, b) => new Date(a.created_at || 0) - new Date(b.created_at || 0));
const recentContextText = historyRowsSorted
  .slice(-6)
  .map((row) => String(row.message || ''))
  .join(' ')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');
const hasTrackedProduct = !!String(customerData.interested_product || merged.interested_product || '').trim();
const hasActiveSalesStage = ['interested', 'closing'].includes(currentStage);
const hasRecentSalesContext = /(iphone|samsung|redmi|poco|pro max|bateria|gb|de contado|contado|cable y cargador|nuevo|seminuevo|como nuevo|\$\s*\d)/.test(recentContextText);
const looksLikeClosingFollowup = /(transfer|transferencia|debito|credito|efectivo|bitcoin|usdt|tarjeta|pago|pagar|contado|envio|despacho|sucursal|retiro|entrega|oran|salta|capital|soy de|soy del interior|me lo mandas|reservo|reserva|sena|seña)/.test(msg);
const shouldKeepSalesContext = looksLikeClosingFollowup && (hasTrackedProduct || hasActiveSalesStage || hasRecentSalesContext);

const patterns = {
  shipping: /ubicaci|direcci|local|donde est|horari|abierto|cerrado|atiend|cu[a\u00e1]ndo abr|envio|env\u00edo|mandan|despach|tracking|seguimiento|rastreo|llega|entrega|llegada|demora|d[i\u00ed]as|cuantos dias|pago|pagar|transfer|efectivo|crypto|bitcoin|usdt|tarjeta|debito|credito|mercado pago|instagram|facebook|rrss|garant[i\u00ed]a|servicio t[e\u00e9]cnico|reparaci[o\u00f3]n/,
  cuotas: /cuota|financi|plazo|mensual|bancariz|macro|6 cuotas|en cuotas|a cuotas|pagar en|naranja|subcredito|sucredito|su credito|tarjeta bancarizada/,
  catalog: /que tienen|qu[e\u00e9] tienen|que modelos|qu[e\u00e9] modelos|que hay|lista|cat[a\u00e1]log|precios de|todos los|ver todo|ver los|tienen iphone|tienen samsung|tienen redmi|tienen poco/,
  sales: /precio|cuanto sale|cu[a\u00e1]nto sale|cuesta|vale|sale el|tiene el|stock|hay|disponible|tenes el|ten[e\u00e9]s el|quiero el|me das|s25|s24|iphone 16|iphone 15|a56|a55|redmi|poco/,
  closing: /lo quiero|quiero comprarlo|c[o\u00f3]mo compro|me lo llevo|dale va|ok lo tomo|voy a llevar|quiero pedirlo|c[o\u00f3]mo pago|para pedir|para comprar/,
  handoff: /hablar con|habla con|joaco|joaqu[i\u00ed]n|una persona|un humano|un asesor|me atienda|ya pagu[e\u00e9]|mi pedido|cuando llega mi|retiro|busco mi|reclamo|queja|devoluci[o\u00f3]n|problema/
};

const matches = {};
let matchCount = 0;
for (const [key, pattern] of Object.entries(patterns)) {
  if (pattern.test(msg)) { matches[key] = true; matchCount++; }
}

let route;
if (humanAssigned) route = 'skip';
else if (isFirstInteraction && (!msg || msg === '(vacio)' || msg === '(mensaje vacio - el cliente abrio el chat)')) route = 'greeting';
else if (shouldKeepSalesContext) route = 'sales';
else if (matchCount >= 2) route = 'sales';
else if (matches.handoff) route = 'handoff';
else if (matches.closing) route = 'sales';
else if (matches.cuotas) route = 'sales';
else if (matches.shipping) route = 'sales';
else if (matches.catalog) route = 'catalog';
else if (matches.sales) route = 'sales';
else route = 'sales';

let response_text = null;
let chatInput = null;
let needs_human = false;
let is_silent = false;

if (route === 'skip') {
  is_silent = true;
} else if (route === 'greeting') {
  response_text = '\ud83d\ude0a \u00a1Hola ' + merged.first_name + '! \u00bfC\u00f3mo and\u00e1s? Bienvenido a TechnoStore Salta \ud83d\udc4b\nContame qu\u00e9 celular est\u00e1s buscando o con qu\u00e9 te puedo ayudar, te atiendo al toque.';
} else if (route === 'handoff') {
  response_text = 'Te paso con un asesor que te va a ayudar \ud83d\ude4c';
  needs_human = true;
} else if (route === 'cuotas') {
  const mentionsNaranja = /naranja/i.test(msg);
  const mentionsSubcredito = /subcredito|sucredito|su credito/i.test(msg);
  if (mentionsSubcredito) {
    response_text = 'No trabajamos con SubCrédito. Sí trabajamos con Naranja, Macro y las demás tarjetas bancarizadas en 6 cuotas fijas, solo presencial en Salta Capital. ¿Qué modelo te interesa así te paso el detalle?';
  } else if (mentionsNaranja) {
    response_text = 'Sí, trabajamos con Naranja. Las cuotas son 6 fijas y solo presencial en Salta Capital. También tenés Macro con precio especial y otras bancarizadas. ¿Qué modelo querés ver?';
  } else {
    response_text = 'Manejamos 6 cuotas fijas presenciales en Salta Capital. Trabajamos con Naranja, Macro y las demás tarjetas bancarizadas. SubCrédito no. ¿Qué modelo te interesa así te paso el valor exacto?';
  }
} else if (route === 'shipping') {
  const info = {
    ubicacion: '📍 ' + storeInfo.address,
    horarios: '🕐 ' + storeInfo.hours,
    pagos: '💳 ' + storeInfo.paymentMethods + ' ' + storeInfo.creditPolicy,
    envios: '📦 ' + storeInfo.shippingPolicy,
    garantia: storeInfo.warrantyNew + ' ' + storeInfo.warrantyUsed,
    redes: '📱 Instagram: ' + storeInfo.instagram + ' | Facebook: ' + storeInfo.facebook,
  };
  if (/garant[i\u00ed]a|servicio t[e\u00e9]cnico|reparaci[o\u00f3]n/.test(msg)) response_text = info.garantia;
  else if (/tracking|seguimiento|rastreo/.test(msg)) response_text = info.envios;
