const data = $('Merge All Routes').first().json;
const metadata = data.metadata || {};
const products = Array.isArray(data.products_list) ? data.products_list : [];
const profile = data.customer_profile || {};

const normalizeText = (value) => String(value || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim();

const normalizeTag = (value) => String(value || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9_-]/g, '_')
  .replace(/_+/g, '_')
  .replace(/^_+|_+$/g, '')
  .trim();

const unique = (items) => [...new Set(items.filter(Boolean))];
const deniedTagKeys = new Set(['loc_interior', 'product_tracked', 'contacted', 'condition_seminuevo_interest']);
const tagDefinitionRows = (() => {
  try {
    const raw = $('Aggregate CRM Tag Definitions').first().json?.tags;
    return Array.isArray(raw) ? raw : [];
  } catch (error) {
    return [];
  }
})();
const allowedTagKeys = new Set(tagDefinitionRows.map((row) => normalizeTag(row.tag_key)).filter(Boolean));
const filterAllowedTags = (tags) => unique(
  tags
    .map((tag) => normalizeTag(tag))
    .filter((tag) => tag && !deniedTagKeys.has(tag) && (allowedTagKeys.size === 0 || allowedTagKeys.has(tag)))
);

const detectPaymentMethods = (...values) => {
  const text = normalizeText(values.filter(Boolean).join(' | '));
  const found = [];
  const add = (key, regex) => {
    if (regex.test(text)) found.push(key);
  };

  add('mercado_pago', /mercado\s*pago|\bmp\b/);
  add('transferencia', /transfer|transfe/);
  if (/efectivo|contado/.test(text)) {
    if (/(usd|dolar)/.test(text)) found.push('efectivo_usd');
    else found.push('efectivo_ars');
  }
  add('bitcoin', /bitcoin|\bbtc\b/);
  add('usdt', /usdt|trc20/);
  add('crypto', /crypto|cripto/);
  add('naranja', /naranja/);
  add('macro', /macro/);
  add('visa', /visa/);
  add('mastercard', /master\s*card|\bmaster\b/);
  add('amex', /amex|american\s*express/);
  add('cabal', /cabal/);
  add('subcredito', /subcredit|sucredit/);
  add('cuotas', /cuotas?|financi/);
  add('tarjeta', /tarjetas?|debito|credito/);
  return unique(found);
};

const detectTopics = ({ intent, userMessage, cleanText, payments }) => {
  const text = normalizeText([userMessage, cleanText].filter(Boolean).join(' | '));
  const topics = [];
  if (/precio|cu[aá]nto|cuanto sale|promo|oferta/.test(text)) topics.push('precio');
  if (/stock|tenes|tienen|hay|disponib|entrega inmediata|a pedido/.test(text)) topics.push('stock');
  if (/foto|fotos|imagen|im[aá]gen|imagenes|mostrame|mostr[aá]|quiero ver/.test(text)) topics.push('imagenes');
  if (/envio|env[ií]o|despacho|oca|via cargo|flecha carga|buspack/.test(text)) topics.push('envio');
  if (/cuotas?|financi|naranja|macro|visa|master|amex|cabal|tarjeta/.test(text)) topics.push('cuotas');
  if (/pago|transfer|mercado pago|efectivo|contado|btc|bitcoin|usdt|cripto/.test(text) || payments.length > 0) topics.push('pago');
  if (/garant/i.test(text)) topics.push('garantia');
  if (/direccion|direcci[oó]n|ubicaci[oó]n|mapa|pin|sucursal|como llego|c[oó]mo llego/.test(text)) topics.push('ubicacion');
  if (/reserv|seña|sena|encargo/.test(text) || intent === 'reservation') topics.push('reserva');
  if (/compar|vs\b|cual conviene|cual me recomendas|cu[aá]l conviene/.test(text) || intent === 'comparison') topics.push('comparacion');
  if (/permuta|tom[aá]s usado|entrego mi celu|trade/.test(text)) topics.push('trade_in');
  if (intent === 'shipping_inquiry') topics.push('envio');
  if (intent === 'cuotas_inquiry') topics.push('cuotas', 'pago');
  if (intent === 'price_inquiry') topics.push('precio');
  if (intent === 'stock_check') topics.push('stock');
  if (intent === 'purchase_intent') topics.push('pago');
  return unique(topics.map((topic) => normalizeTag(topic))).slice(0, 6);
};

const detectBrands = ({ brandInterest, products, userMessage, cleanText }) => {
  const text = normalizeText([brandInterest, products.join(' '), userMessage, cleanText].filter(Boolean).join(' | '));
  const brands = [];
  if (/iphone|apple/.test(text)) brands.push('iphone');
  if (/samsung/.test(text)) brands.push('samsung');
  if (/redmi|poco|xiaomi/.test(text)) brands.push('redmi_poco');
  return unique(brands);
};

const stageRank = { new: 0, browsing: 1, interested: 2, closing: 3, human_handoff: 4 };
const now = new Date().toISOString();
const currentStage = normalizeText(data.current_funnel_stage || profile.funnel_stage || '');
const requestedStage = normalizeText(metadata.funnel_update || '');
const userMessage = String(data.user_message || '');
const cleanText = String(data.clean_text || '');
const currentInteractions = Number(profile.total_interactions || 0);
const phoneAreaCode = String(data.phone_area_code || profile.phone_area_code || '').trim();
const phoneAreaName = String(data.phone_area_name || profile.phone_area_name || '').trim();
const phoneAreaProvince = String(data.phone_area_province || profile.phone_area_province || '').trim();
const detectedPayments = detectPaymentMethods(metadata.payment_method, userMessage, cleanText);
const detectedBrands = detectBrands({ brandInterest: metadata.brand_interest, products, userMessage, cleanText });
const detectedTopics = detectTopics({ intent: metadata.intent, userMessage, cleanText, payments: detectedPayments });

const updates = {
  last_bot_interaction: now,
  updated_at: now,
};

if (!profile.first_seen_at) updates.first_seen_at = now;
if (!profile.lead_source) updates.lead_source = 'manychat';

if (requestedStage && requestedStage !== 'no_change') {
  if (stageRank[requestedStage] !== undefined) {
    if (stageRank[currentStage] === undefined || stageRank[requestedStage] >= stageRank[currentStage]) {
      updates.funnel_stage = requestedStage;
      updates.last_funnel_change_at = now;
    }
  }
}

const effectiveFunnel = String(updates.funnel_stage || currentStage || 'new');
if (effectiveFunnel === 'browsing' && !profile.browsing_at) updates.browsing_at = now;
if (effectiveFunnel === 'interested' && !profile.interested_at) updates.interested_at = now;
if (effectiveFunnel === 'closing' && !profile.closing_at) updates.closing_at = now;
if (effectiveFunnel === 'human_handoff' && !profile.human_handoff_at) updates.human_handoff_at = now;

if (metadata.city_detected && metadata.city_detected !== 'none') {
  let city = String(metadata.city_detected).trim();
  const lower = normalizeText(city);
  if (['salta', 'salta capital', 'salta cap'].includes(lower)) {
    city = 'Salta Capital';
    updates.is_salta_capital = true;
    updates.location_source = 'explicit_city';
  } else {
    updates.location_source = 'explicit_city';
  }
  updates.city = city;
}
if (metadata.is_salta === 'true') updates.is_salta_capital = true;
else if (metadata.is_salta === 'false') updates.is_salta_capital = false;
if (phoneAreaCode) updates.phone_area_code = phoneAreaCode;
if (phoneAreaName) updates.phone_area_name = phoneAreaName;
if (phoneAreaProvince) updates.phone_area_province = phoneAreaProvince;
if (!updates.location_source) {
  updates.location_source = metadata.city_detected && metadata.city_detected !== 'none'
    ? 'explicit_city'
    : phoneAreaCode
      ? 'phone_area_code'
      : 'unknown';
}

if (metadata.brand_interest && metadata.brand_interest !== 'none') updates.preferred_brand = metadata.brand_interest;
if (metadata.budget_hint && metadata.budget_hint !== 'none') updates.preferred_budget = metadata.budget_hint;
if (products.length > 0) updates.interested_product = products[0];

const existingPayments = Array.isArray(profile.payment_methods_mentioned) ? profile.payment_methods_mentioned : [];
const paymentMethodsMentioned = unique([...existingPayments, ...detectedPayments]).slice(0, 12);
if (paymentMethodsMentioned.length > 0) updates.payment_methods_mentioned = paymentMethodsMentioned;
if (detectedPayments.length > 0) {
  updates.payment_method_last = detectedPayments[0];
  updates.payment_preference = detectedPayments[0];
}

const existingProducts = Array.isArray(profile.products_mentioned) ? profile.products_mentioned : [];
const mergedProducts = unique([...products, ...existingProducts]).slice(0, 12);
if (mergedProducts.length > 0) updates.products_mentioned = mergedProducts;

const existingBrands = Array.isArray(profile.brands_mentioned) ? profile.brands_mentioned : [];
const mergedBrands = unique([...detectedBrands, ...existingBrands]).slice(0, 6);
if (mergedBrands.length > 0) updates.brands_mentioned = mergedBrands;

const existingTopics = Array.isArray(profile.topics_mentioned) ? profile.topics_mentioned : [];
const mergedTopics = unique([...detectedTopics, ...existingTopics]).slice(0, 12);
if (mergedTopics.length > 0) updates.topics_mentioned = mergedTopics;

if (metadata.intent && metadata.intent !== 'ambiguous') updates.last_intent = metadata.intent;

try {
  const mergedData = $('Merge & Aggregate Messages').first().json;
  if (mergedData.subscribed_at && !profile.manychat_subscribed_at) {
    updates.manychat_subscribed_at = mergedData.subscribed_at;
  }
} catch (error) {}

let score = 0;
score += Math.min(currentInteractions + 1, 20);
if (mergedBrands.length > 0) score += 5;
if (products.length > 0) score += 10;
if (metadata.is_salta === 'true' || profile.is_salta_capital) score += 10;
if (['interested', 'closing'].includes(effectiveFunnel)) score += 15;
if (effectiveFunnel === 'closing') score += 10;
if (metadata.intent === 'purchase_intent') score += 25;
if (metadata.intent === 'reservation') score += 20;
if (metadata.intent === 'cuotas_inquiry') score += 15;
if (detectedPayments.length > 0) score += 10;
if (detectedTopics.includes('ubicacion')) score += 4;
if (detectedTopics.includes('imagenes')) score += 4;
if (data.was_audio) score += 2;
if (data.needs_human && metadata.intent !== 'complaint') score += 20;
updates.lead_score = score;

const newTags = [];
if (metadata.brand_interest && metadata.brand_interest !== 'none') newTags.push('brand_' + normalizeTag(metadata.brand_interest));
if (metadata.intent && metadata.intent !== 'none') newTags.push('intent_' + normalizeTag(metadata.intent));
if (effectiveFunnel && effectiveFunnel !== 'no_change') newTags.push('stage_' + normalizeTag(effectiveFunnel));
if (metadata.is_salta === 'true' || profile.is_salta_capital) newTags.push('loc_salta_capital');
if (data.was_audio) newTags.push('behavior_audio_user');
if (phoneAreaCode) newTags.push('phone_area_known');
if (phoneAreaProvince) newTags.push('prov_' + normalizeTag(phoneAreaProvince));
for (const method of detectedPayments) newTags.push('pay_' + normalizeTag(method));
for (const topic of detectedTopics) newTags.push('topic_' + normalizeTag(topic));
if (data.needs_human) newTags.push('needs_human');
const existingTags = filterAllowedTags(Array.isArray(profile.tags) ? profile.tags : []);
const mergedTags = filterAllowedTags([...existingTags, ...newTags]).slice(0, 64);
const conversationAppliedTags = filterAllowedTags(newTags).filter((tag) => !existingTags.includes(tag));
updates.tags = mergedTags;

if (!data.needs_human && profile.human_assigned === true) {
  try {
    const mergedInput = $('Merge & Aggregate Messages').first().json;
    if (mergedInput.is_human_active === false || !mergedInput.is_human_active) {
      updates.human_assigned = false;
    }
  } catch (error) {
    updates.human_assigned = false;
  }
}

if (data.needs_human) {
  updates.human_assigned = true;
  updates.funnel_stage = 'human_handoff';
  updates.human_handoff_at = profile.human_handoff_at || now;
  updates.last_human_interaction = now;
  updates.last_funnel_change_at = now;
}

return [{ json: { subscriber_id: data.subscriber_id, updates, conversation_applied_tags: conversationAppliedTags } }];

const data = $('Merge All Routes').first().json;
const metadata = data.metadata || {};

const saveNode = $('Save Incoming Message').first();
let savedId = null;
const savedBody = saveNode.json;
if (Array.isArray(savedBody) && savedBody.length > 0) {
  savedId = savedBody[0]?.id;
} else if (savedBody && savedBody.id) {
