}

const intent = String(metadata.intent || '').trim();
if (!savedId || !intent) {
  return [];
}

return [{
  json: {
    message_id: savedId,
    intent
  }
}];

const upsertRaw = $input.first().json;

const toIntOrNull = (value) => {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
};

const extractCustomerId = (raw) => {
  if (typeof raw === 'number' && Number.isFinite(raw)) return raw;
  if (typeof raw === 'string') return toIntOrNull(raw);
  if (Array.isArray(raw) && raw.length > 0) {
    const first = raw[0];
    if (typeof first === 'number' && Number.isFinite(first)) return first;
    if (typeof first === 'string') return toIntOrNull(first);
    if (first && typeof first === 'object') {
      if (first.upsert_customer !== undefined && first.upsert_customer !== null) return toIntOrNull(first.upsert_customer);
      if (first.customer_id !== undefined && first.customer_id !== null) return toIntOrNull(first.customer_id);
      if (first.id !== undefined && first.id !== null) return toIntOrNull(first.id);
    }
  }
  if (raw && typeof raw === 'object') {
    if (raw.upsert_customer !== undefined && raw.upsert_customer !== null) return toIntOrNull(raw.upsert_customer);
    if (raw.customer_id !== undefined && raw.customer_id !== null) return toIntOrNull(raw.customer_id);
    if (raw.id !== undefined && raw.id !== null) return toIntOrNull(raw.id);
  }
  return null;
};

const customerId = extractCustomerId(upsertRaw);

const saveNode = $('Save Incoming Message').first();
const savedBody = saveNode.json;
let messageId = null;
if (Array.isArray(savedBody) && savedBody.length > 0) {
  messageId = savedBody[0]?.id;
} else if (savedBody && savedBody.id) {
  messageId = savedBody.id;
}

const parsedMessageId = toIntOrNull(messageId);
if (!Number.isFinite(customerId) || !Number.isFinite(parsedMessageId)) {
  return [];
}

return [{
  json: {
    message_id: parsedMessageId,
    customer_id: customerId
  }
}];

const data = $('Merge All Routes').first().json;
const metadata = data.metadata || {};
const products = Array.isArray(data.products_list) ? data.products_list : [];
const profile = data.customer_profile || {};

const normalizeText = (value) => String(value || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim();

const unique = (items) => [...new Set(items.filter(Boolean))];

const detectPaymentMethods = (...values) => {
  const text = normalizeText(values.filter(Boolean).join(' | '));
  const found = [];
  const add = (key, regex) => {
    if (regex.test(text)) found.push(key);
  };

  add('mercado_pago', /mercado\s*pago|\bmp\b/);
  add('transferencia', /transfer|transfe/);
  if (/efectivo|contado/.test(text)) {
    if (/(usd|dolar)/.test(text)) found.push('efectivo_usd');
    else found.push('efectivo_ars');
  }
  add('bitcoin', /bitcoin|\bbtc\b/);
  add('usdt', /usdt|trc20/);
  add('crypto', /crypto|cripto/);
  add('naranja', /naranja/);
  add('macro', /macro/);
  add('visa', /visa/);
  add('mastercard', /master\s*card|\bmaster\b/);
  add('amex', /amex|american\s*express/);
  add('cabal', /cabal/);
  add('subcredito', /subcredit|sucredit/);
  add('cuotas', /cuotas?|financi/);
  add('tarjeta', /tarjetas?|debito|credito/);
  return unique(found);
};

const numberFields = new Set(['lead_score', 'interaction_count']);
const fields = [];
const add = (name, value) => {
  if (value === undefined || value === null) return;
  if (numberFields.has(name)) {
    const numberValue = typeof value === 'number' ? value : Number(String(value).trim());
    if (!Number.isFinite(numberValue)) return;
    fields.push({ field_name: name, field_value: numberValue });
    return;
  }

  const stringValue = String(value).trim();
  if (!stringValue || ['none', 'no_change', 'unknown'].includes(stringValue.toLowerCase())) return;
  fields.push({ field_name: name, field_value: stringValue });
};

const payments = detectPaymentMethods(metadata.payment_method, data.user_message, data.clean_text);
const paymentList = unique([...(Array.isArray(profile.payment_methods_mentioned) ? profile.payment_methods_mentioned : []), ...payments]);
const currentStage = String(metadata.funnel_update || profile.funnel_stage || 'new').toLowerCase();
const interactions = Number(profile.total_interactions || 0) + 1;
const phoneAreaCode = String(data.phone_area_code || profile.phone_area_code || '').trim();
const phoneAreaName = String(data.phone_area_name || profile.phone_area_name || '').trim();
const phoneAreaProvince = String(data.phone_area_province || profile.phone_area_province || '').trim();
const locationSource = profile.location_source || (phoneAreaCode ? 'phone_area_code' : 'unknown');

if (currentStage && currentStage !== 'no_change') add('funnel_stage', currentStage);
if (metadata.brand_interest) add('brand', metadata.brand_interest);
if (metadata.city_detected) add('city', metadata.city_detected);
if (metadata.is_salta && metadata.is_salta !== 'unknown') add('is_salta', metadata.is_salta);
if (metadata.budget_hint) add('budget_range', metadata.budget_hint);
if (payments[0]) add('payment_method', payments[0]);
if (paymentList.length > 0) add('payment_methods_mentioned', paymentList.join(','));
if (phoneAreaCode) add('phone_area_code', phoneAreaCode);
if (phoneAreaName) add('phone_area_name', phoneAreaName);
if (phoneAreaProvince) add('phone_area_province', phoneAreaProvince);
if (metadata.intent) add('last_intent', metadata.intent);
if (products.length > 0) {
  add('interested_product', products[0]);
  add('last_product_viewed', products[0]);
  add('products_mentioned', products.join(','));
}
add('interaction_count', interactions);
add('location_source', locationSource);

let score = 0;
score += Math.min(interactions, 20);
if (metadata.brand_interest && metadata.brand_interest !== 'none') score += 5;
if (products.length > 0) score += 10;
if (metadata.is_salta === 'true' || profile.is_salta_capital) score += 10;
if (['interested', 'closing'].includes(currentStage)) score += 15;
if (currentStage === 'closing') score += 10;
if (metadata.intent === 'purchase_intent') score += 25;
if (metadata.intent === 'reservation') score += 20;
if (metadata.intent === 'cuotas_inquiry') score += 15;
if (payments.length > 0) score += 10;
add('lead_score', score);

if (data.needs_human) {
  add('is_human_active', 'true');
  add('funnel_stage', 'human_handoff');
}

if (fields.length === 0) return [];
return [{ json: { subscriber_id: String(data.subscriber_id), fields } }];

const rows = [];
for (const item of $input.all()) {
  let data = item.json;
  if (data && data.data && Array.isArray(data.data)) data = data.data;
  if (Array.isArray(data)) rows.push(...data);
  else if (data && data.tag_key) rows.push(data);
}
return [{ json: { tags: rows } }];
